// ── Limpieza HTML → texto plano antes de enviar al GPT ──────────────────────
// Evita el error: "messages resulted in 172485 tokens" (límite 128000)
// Los correos llegan como HTML completo con estilos, scripts y cadenas de reply.
// Este nodo extrae solo el texto útil y lo recorta a 3000 caracteres máximo.

const MAX_CHARS = 3000;

function htmlToText(html) {
  if (!html || typeof html !== 'string') return '';

  return html
    // Eliminar bloques <style> y <script> con su contenido
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    // Eliminar head completo
    .replace(/<head[^>]*>[\s\S]*?<\/head>/gi, ' ')
    // Convertir saltos de bloque en espacios
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/?(p|div|li|tr|td|th|h[1-6])[^>]*>/gi, ' ')
    // Eliminar todos los tags restantes
    .replace(/<[^>]+>/g, '')
    // Decodificar entidades HTML básicas
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    // Colapsar espacios y saltos redundantes
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function truncate(text, max) {
  if (!text || text.length <= max) return text;
  // Cortar en el último espacio antes del límite para no partir palabras
  const cut = text.lastIndexOf(' ', max);
  return text.slice(0, cut > 0 ? cut : max) + ' [...]';
}

const raw = $json.body_content || $json.descripcion || '';
const textoLimpio = truncate(htmlToText(raw), MAX_CHARS) || 'Sin contenido';

return [{ json: {
  ...$json,
  texto_para_gpt: textoLimpio
}}];

const correoId = $('¿Hay PQR para clasificar?1').first().json.id;
const raw = $input.first().json.choices?.[0]?.message?.content || 
            $input.first().json.message?.content || '{}';

let clasificacion;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  clasificacion = JSON.parse(cleaned);
} catch(e) {
  clasificacion = {
    tipo_pqr: 'peticion',
    prioridad: 'media',
    sentimiento: 'neutro',
    categoria_ia: 'otro',
    resumen_corto: 'Sin clasificar',
    es_urgente: false,
    nivel_riesgo: 'ninguno',
    ley_aplicable: 'Ley 1755/2015',
    horas_sla: 120
  };
}

// ── Validaciones de tipo y formato ──────────────────────────────────────────
if (typeof clasificacion.es_urgente !== 'boolean') clasificacion.es_urgente = false;
if (!clasificacion.horas_sla || isNaN(clasificacion.horas_sla)) clasificacion.horas_sla = 120;
if (!clasificacion.nivel_riesgo) clasificacion.nivel_riesgo = 'ninguno';
if (!clasificacion.ley_aplicable) clasificacion.ley_aplicable = 'Ley 1755/2015';

// ── Reglas defensivas SLA ────────────────────────────────────────────────────

// QUEJA: nunca puede tener nivel_riesgo=ninguno ni horas_sla=120
if (clasificacion.tipo_pqr === 'queja') {
  if (!['vital','priorizado','simple'].includes(clasificacion.nivel_riesgo)) {
    clasificacion.nivel_riesgo = 'simple';
    clasificacion.horas_sla    = 72;
    clasificacion.es_urgente   = false;
  }
  if (clasificacion.nivel_riesgo === 'vital'      && clasificacion.horas_sla !== 24)  clasificacion.horas_sla = 24;
  if (clasificacion.nivel_riesgo === 'priorizado' && clasificacion.horas_sla !== 48)  clasificacion.horas_sla = 48;
  if (clasificacion.nivel_riesgo === 'simple'     && clasificacion.horas_sla !== 72)  clasificacion.horas_sla = 72;
  if (clasificacion.nivel_riesgo === 'vital' || clasificacion.nivel_riesgo === 'priorizado') {
    clasificacion.es_urgente = true;
  } else {
    clasificacion.es_urgente = false;
  }
}

// DENUNCIA: siempre 120h hábiles
if (clasificacion.tipo_pqr === 'denuncia') {
  clasificacion.horas_sla     = 120;
  clasificacion.nivel_riesgo  = 'ninguno';
  clasificacion.es_urgente    = false;
  clasificacion.ley_aplicable = 'Ley 1755/2015 + vigilancia sanitaria';
}

// PETICIÓN con nivel vital/priorizado → reclasificar como queja
if (clasificacion.tipo_pqr === 'peticion' &&
    ['vital','priorizado'].includes(clasificacion.nivel_riesgo)) {
  clasificacion.tipo_pqr      = 'queja';
  clasificacion.ley_aplicable = 'Ley 1755/2015';
  clasificacion.es_urgente    = true;
}

// RECLAMO: ley y horas correctas
if (clasificacion.tipo_pqr === 'reclamo') {
  clasificacion.ley_aplicable = 'Ley 1755/2015 + Ley 1751/2015';
  if (!clasificacion.horas_sla || clasificacion.horas_sla !== 120) clasificacion.horas_sla = 120;
}

return [{ json: { correo_id: correoId, ...clasificacion } }];

// Calcula fecha límite SLA considerando horas hábiles Colombia
// <64h = horas corridas (queja vital 24h, queja priorizada 48h, queja simple 72h)
// >=64h = horas hábiles lun-vie 8am-6pm UTC-5 Bogotá

const horasSla = $json.horas_sla || 120;
const esHabilSolo = horasSla >= 64;

function addBusinessHours(date, hours) {
  const TZ_OFFSET = -5;
  let remaining = hours;
  let current = new Date(date);
  while (remaining > 0) {
    current.setHours(current.getHours() + 1);
    const localHour = (current.getUTCHours() + 24 + TZ_OFFSET) % 24;
    const dow = current.getUTCDay();
    const isWorkday = dow >= 1 && dow <= 5;
    const isWorkHour = localHour >= 8 && localHour < 18;
    if (esHabilSolo ? (isWorkday && isWorkHour) : true) remaining--;
  }
  return current;
}

const fechaLimite = addBusinessHours(new Date(), horasSla);

return [{ json: {
  ...$input.first().json,
  fecha_limite_sla: fechaLimite.toISOString()
}}];
